func (f *CommandFactory) newAgentRunCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:          "run",
		Short:        "Invoke an agent with a prompt",
		SilenceUsage: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			promptFile, _ := cmd.Flags().GetString("prompt")
			promptText, _ := cmd.Flags().GetString("text")
			harness, _ := cmd.Flags().GetString("harness")
			model, _ := cmd.Flags().GetString("model")
			profile, _ := cmd.Flags().GetString("profile")
			effort, _ := cmd.Flags().GetString("effort")
			timeoutStr, _ := cmd.Flags().GetString("timeout")
			quorum, _ := cmd.Flags().GetString("quorum")
			harnesses, _ := cmd.Flags().GetString("harnesses")
			asJSON, _ := cmd.Flags().GetBool("json")
			outputFmt, _ := cmd.Flags().GetString("output")
			worktreeName, _ := cmd.Flags().GetString("worktree")
			permissions, _ := cmd.Flags().GetString("permissions")
			compare, _ := cmd.Flags().GetBool("compare")
			sandbox, _ := cmd.Flags().GetBool("sandbox")
			keepSandbox, _ := cmd.Flags().GetBool("keep-sandbox")
			postRun, _ := cmd.Flags().GetString("post-run")
			arms, _ := cmd.Flags().GetStringArray("arm")

			var timeout time.Duration
			if timeoutStr != "" {
				var err error
				timeout, err = time.ParseDuration(timeoutStr)
				if err != nil {
					return fmt.Errorf("invalid timeout: %w", err)
				}
			}

			// Resolve project root (--project flag > DDX_PROJECT_ROOT > CWD git root)
			projectFlag, _ := cmd.Flags().GetString("project")
			workDir := resolveProjectRoot(projectFlag, f.WorkingDir)
			if worktreeName != "" {
				wtPath, err := resolveWorktree(workDir, worktreeName)
				if err != nil {
					return fmt.Errorf("worktree: %w", err)
				}
				workDir = wtPath
			}

			// Read prompt from stdin if neither file nor text provided
			prompt := promptText
			promptSource := "inline"
			if prompt == "" && promptFile == "" {
				// Check if stdin has data
				stat, _ := os.Stdin.Stat()
				if (stat.Mode() & os.ModeCharDevice) == 0 {
					data, err := io.ReadAll(os.Stdin)
					if err != nil {
						return fmt.Errorf("reading stdin: %w", err)
					}
					prompt = string(data)
					promptSource = "stdin"
				}
			} else if promptFile != "" {
				promptSource = promptFile
			}

			// Comparison mode
			if compare {
				var harnessNames []string
				armModels := map[int]string{}
				armLabels := map[int]string{}

				// Parse --arm flags: "harness:model:label" or "harness:model" or "harness"
				if len(arms) > 0 {
					for i, arm := range arms {
						parts := strings.SplitN(arm, ":", 3)
						harnessNames = append(harnessNames, parts[0])
						if len(parts) >= 2 && parts[1] != "" {
							armModels[i] = parts[1]
						}
						if len(parts) >= 3 {
							armLabels[i] = parts[2]
						} else if len(parts) >= 2 && parts[1] != "" {
							armLabels[i] = parts[0] + "/" + parts[1]
						}
					}
				} else if harnesses != "" {
					harnessNames = strings.Split(harnesses, ",")
				} else {
					return fmt.Errorf("--arm or --harnesses required for --compare mode")
				}

				overrides := config.CLIOverrides{
					Model:       model,
					Effort:      effort,
					Permissions: permissions,
				}
				if timeout > 0 {
					overrides.Timeout = &timeout
				}
				rcfg, _ := config.LoadAndResolve(f.WorkingDir, overrides)
				runtime := agent.CompareRuntime{
					AgentRunRuntime: agent.AgentRunRuntime{
						Prompt:       prompt,
						PromptFile:   promptFile,
						PromptSource: promptSource,
						WorkDir:      workDir,
					},
					Harnesses:   harnessNames,
					ArmModels:   armModels,
					ArmLabels:   armLabels,
					Sandbox:     sandbox,
					KeepSandbox: keepSandbox,
					PostRun:     postRun,
				}
				record, err := agent.RunCompareWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
				if err != nil {
					return err
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(record)
				}
				fmt.Fprintf(cmd.OutOrStdout(), "Comparison %s (%d arms)\n", record.ID, len(record.Arms))
				for _, arm := range record.Arms {
					status := "OK"
					if arm.ExitCode != 0 {
						status = fmt.Sprintf("FAIL (rc=%d)", arm.ExitCode)
					}
					cost := ""
					if arm.CostUSD > 0 {
						cost = fmt.Sprintf(" cost=$%.4f", arm.CostUSD)
					}

			CostClass:    h.CostClass,
			Quota:        formatQuotaState(h.Quota),
			Usage:        formatUsageWindows(h.UsageWindows),
		}
		if h.LastError != nil {
			row.Error = h.LastError.Detail
		}
		rows = append(rows, row)
	}
	sort.Slice(rows, func(i, j int) bool { return rows[i].Name < rows[j].Name })
	return rows
}

func routeStatusModelsJSON(models []agentlib.ModelInfo) []routeStatusModelJSON {
	rows := make([]routeStatusModelJSON, 0, len(models))
	for _, m := range models {
		rows = append(rows, routeStatusModelJSON{
			Provider:             m.Provider,
			Harness:              m.Harness,
			Model:                m.ID,
			Available:            m.Available,
			AutoRoutable:         m.AutoRoutable,
			Power:                m.Power,
			InputCostPerMTokUSD:  m.Cost.InputPerMTok,
			OutputCostPerMTokUSD: m.Cost.OutputPerMTok,
			SpeedTokensPerSec:    m.PerfSignal.SpeedTokensPerSec,
			CatalogRef:           m.CatalogRef,
			RankPosition:         m.RankPosition,
		})
	}
	sort.Slice(rows, func(i, j int) bool {
		if rows[i].Provider != rows[j].Provider {
			return rows[i].Provider < rows[j].Provider
		}
		return rows[i].Model < rows[j].Model
	})
	return rows
}

func providerCooldowns(providers []agentlib.ProviderInfo) []routeStatusCooldown {
	var out []routeStatusCooldown
	for _, p := range providers {
		if p.CooldownState == nil || p.CooldownState.Until.IsZero() || time.Now().After(p.CooldownState.Until) {
			continue
		}
		out = append(out, routeStatusCooldown{provider: p.Name, cooldownUntil: p.CooldownState.Until})
	}
	sort.Slice(out, func(i, j int) bool { return out[i].provider < out[j].provider })
	return out
}

func formatQuotaState(q *agentlib.QuotaState) string {
	if q == nil {
		return "-"
	}
	status := q.Status
	if status == "" {
		status = "unknown"
	}
	if len(q.Windows) == 0 {
		return status
	}
	best := q.Windows[0]
	for _, w := range q.Windows[1:] {
		if w.UsedPercent > best.UsedPercent {
			best = w
		}
	}
	if best.UsedPercent > 0 {
		return fmt.Sprintf("%s %.0f%% %s", status, best.UsedPercent, best.Name)
	}
	return status
}

func formatUsageWindows(windows []agentlib.UsageWindow) string {
	if len(windows) == 0 {
		return "-"
	}
	w := windows[0]
	for _, candidate := range windows {
		if candidate.Name == "7d" {
			w = candidate
			break
		}
	}
	parts := []string{}
	if w.TotalTokens > 0 {
		parts = append(parts, fmt.Sprintf("%dtok", w.TotalTokens))
	}
	if w.CostUSD > 0 {
		parts = append(parts, fmt.Sprintf("$%.4f", w.CostUSD))
	}
	if len(parts) == 0 {
		return "-"
	}
	if w.Name != "" {
		parts = append(parts, w.Name)
	}
	return strings.Join(parts, " ")
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if v != "" {
			return v
		}
	}
	return ""
}

func formatCostPerMTok(v float64) string {
	if v <= 0 {
		return "-"
	}
	return fmt.Sprintf("%.2f", v)
}

func truncateRouteStr(value string, n int) string {
	if n <= 0 || len(value) <= n {
		return value
	}
	if n <= 2 {
		return value[:n]
	}
	return value[:n-2] + ".."
}

func (f *CommandFactory) newAgentRouteStatusCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "route-status",
		Short: "Show live provider/model routing status",
		Long: `Shows the live provider and model inventory used by Fizeau routing:
provider status, presented models, power, cost, usage, quota, recent decisions,
and active cooldowns.

	Examples:
	  ddx agent route-status
	  ddx agent route-status --model qwen3.5-27b
	  ddx agent route-status --json`,
		Args: cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			model, _ := cmd.Flags().GetString("model")
			asJSON, _ := cmd.Flags().GetBool("json")

			svc, err := agent.NewServiceFromWorkDir(f.WorkingDir)
			if err != nil {
				return fmt.Errorf("loading agent config: %w", err)
			}

			ctx := context.Background()
			providers, err := svc.ListProviders(ctx)
			if err != nil {
				return fmt.Errorf("listing providers: %w", err)
			}
			harnesses, err := svc.ListHarnesses(ctx)
			if err != nil {
				return fmt.Errorf("listing harnesses: %w", err)
			}
			models, err := svc.ListModels(ctx, agentlib.ModelFilter{})
			if err != nil {
				return fmt.Errorf("listing models: %w", err)
			}
			if model != "" {
				filtered := models[:0]
				for _, m := range models {
					if m.ID == model {
						filtered = append(filtered, m)
					}
				}
				models = filtered
			}

			var selection *routeStatusSelectionJSON
			if decision, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{}); err == nil && decision != nil {
				selection = &routeStatusSelectionJSON{
					Harness:  decision.Harness,
					Provider: decision.Provider,
					Endpoint: decision.Endpoint,
					Model:    decision.Model,
					Power:    decision.Power,
					Reason:   decision.Reason,
				}
			}

			// Load recent routing decisions from two complementary sources:
			//
			//  1. RoutingMetricsStore — harness-level analytics (latency, success
			//     rate) for every agent run, stored in routing-outcomes.jsonl.
			//  2. kind:routing bead events — execution provenance per bead (which
			//     provider/model was selected and why), tied to a specific bead ID.
			var recentDecisions []recentRoutingDecision

			if logDir := agent.SessionLogDirForWorkDir(f.WorkingDir); logDir != "" {
				store := agent.NewRoutingMetricsStore(logDir)
				outcomes, _ := store.ReadOutcomes()
				for _, o := range outcomes {
					recentDecisions = append(recentDecisions, recentRoutingDecision{
						ObservedAt:   o.ObservedAt,
						Source:       "metrics-store",
						Harness:      o.Harness,
						Provider:     o.CanonicalTarget,
						Model:        o.Model,
						Success:      o.Success,
						SuccessKnown: true,
						LatencyMS:    o.LatencyMS,
					})
				}
			}

			// Merge kind:routing bead evidence entries.
			recentDecisions = append(recentDecisions, beadRoutingDecisionsFromStore(f.WorkingDir)...)

			// Sort by time and take the last N.
			sort.Slice(recentDecisions, func(i, j int) bool {
				return recentDecisions[i].ObservedAt.Before(recentDecisions[j].ObservedAt)
			})
			const maxRecent = 10
			if len(recentDecisions) > maxRecent {
				recentDecisions = recentDecisions[len(recentDecisions)-maxRecent:]
			}

			activeCooldowns := providerCooldowns(providers)

			if asJSON {
				payload := routeStatusJSON{Selection: selection}
				payload.Providers = routeStatusProvidersJSON(providers, harnesses)
				payload.Models = routeStatusModelsJSON(models)
				for _, d := range recentDecisions {
					jd := routeStatusDecisionJSON{
						ObservedAt:  d.ObservedAt.UTC().Format(time.RFC3339),
						Source:      d.Source,
						BeadID:      d.BeadID,
						Harness:     d.Harness,
						Provider:    d.Provider,
						Model:       d.Model,
						RouteReason: d.RouteReason,
					}
					if d.Source == "metrics-store" {
						jd.CanonicalTarget = d.Provider
						jd.Success = d.Success
						jd.LatencyMs = d.LatencyMS
					}
					payload.RecentDecisions = append(payload.RecentDecisions, jd)
				}
				for _, c := range activeCooldowns {
					cd := routeStatusCooldownJSON{
						Provider:      c.provider,
						CooldownUntil: c.cooldownUntil.UTC().Format(time.RFC3339),
					}
					payload.ActiveCooldowns = append(payload.ActiveCooldowns, cd)
				}
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(payload)
			}

			out := cmd.OutOrStdout()
			if selection != nil {
				fmt.Fprintf(out, "Selected: %s/%s", selection.Provider, selection.Model)
				if selection.Harness != "" {
					fmt.Fprintf(out, " via %s", selection.Harness)
				}
				if selection.Power > 0 {
					fmt.Fprintf(out, " power=%d", selection.Power)
				}
				if selection.Reason != "" {
					fmt.Fprintf(out, " (%s)", selection.Reason)
				}
				fmt.Fprintln(out)
			} else {
				fmt.Fprintln(out, "Selected: (none)")
			}
			fmt.Fprintln(out)

			fmt.Fprintln(out, "Providers")
			fmt.Fprintf(out, "%-24s %-12s %-14s %-11s %-18s %s\n",
				"PROVIDER", "TYPE", "STATUS", "COST", "QUOTA", "USAGE")
			for _, p := range routeStatusProvidersJSON(providers, harnesses) {
				fmt.Fprintf(out, "%-24s %-12s %-14s %-11s %-18s %s\n",
					truncateRouteStr(p.Name, 24),
					truncateRouteStr(p.Type, 12),

	freshness := "fresh"
	if !info.Quota.Fresh {
		freshness = "stale"
	}
	if info.Quota.Status == "unavailable" || info.Quota.Status == "unauthenticated" {
		freshness = "unknown"
	}

	kind := info.Quota.Source
	if kind == "" {
		kind = "stats-cache"
	}

	var ageSeconds int64
	if !info.Quota.CapturedAt.IsZero() {
		if age := now.UTC().Sub(info.Quota.CapturedAt.UTC()); age > 0 {
			ageSeconds = int64(age.Seconds())
		}
	}

	meta := agent.SignalSourceMetadata{
		Provider:   info.Name,
		Kind:       kind,
		ObservedAt: info.Quota.CapturedAt.UTC(),
		Freshness:  freshness,
		AgeSeconds: ageSeconds,
	}
	snap.Source = meta
	snap.CurrentQuota = agent.QuotaSignal{
		Source:        meta,
		State:         state,
		UsedPercent:   usedPercent,
		WindowMinutes: windowMinutes,
		ResetsAt:      resetsAt,
	}

	for _, u := range info.UsageWindows {
		snap.HistoricalUsage.InputTokens += u.InputTokens
		snap.HistoricalUsage.OutputTokens += u.OutputTokens
		snap.HistoricalUsage.TotalTokens += u.TotalTokens
	}
	snap.HistoricalUsage.Source = meta

	return snap
}

func buildProviderSummary(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes []agent.RoutingOutcome,
	now time.Time,
) ProviderSummary {
	harnessOutcomes := filterProviderOutcomes(outcomes, info.Name, now, 7)
	perf := computeProviderPerformance(harnessOutcomes)
	sources := collectProviderSignalSources(signal, len(harnessOutcomes) > 0)

	var freshnessTS string
	if ts := providerFreshnessTS(signal, harnessOutcomes); !ts.IsZero() {
		freshnessTS = ts.UTC().Format(time.RFC3339)
	}

	return ProviderSummary{
		Harness:            info.Name,
		DisplayName:        harnessDisplayName(info.Name),
		Status:             providerStatusStrInfo(info),
		AuthState:          providerAuthStateStr(signal),
		QuotaHeadroom:      providerQuotaHeadroomStr(signal),
		SignalSources:      sources,
		FreshnessTS:        freshnessTS,
		LastCheckedTS:      now.UTC().Format(time.RFC3339),
		RecentSuccessRate:  perf.SuccessRate,
		RecentLatencyP50MS: perf.P50LatencyMS,
		CostClass:          harnessCosCostClassStr(info),
	}
}

func buildProviderDetail(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes []agent.RoutingOutcome,
	burnSummaries []agent.BurnSummary,
	now time.Time,
) ProviderDetail {
	outcomes7d := filterProviderOutcomes(outcomes, info.Name, now, 7)
	outcomes30d := filterProviderOutcomes(outcomes, info.Name, now, 30)
	perf := computeProviderPerformance(outcomes7d)
	sources := collectProviderSignalSources(signal, len(outcomes7d) > 0)

	var freshnessTS string
	if ts := providerFreshnessTS(signal, outcomes7d); !ts.IsZero() {
		freshnessTS = ts.UTC().Format(time.RFC3339)
	}

	models := buildModelQuotaList(info, signal)
	historicalUsage := computeProviderHistoricalUsage(info, signal, outcomes7d, outcomes30d)
	burnEstimate := computeProviderBurnEstimate(info, burnSummaries, historicalUsage, signal)

	statusStr := providerStatusStrInfo(info)
	return ProviderDetail{
		Harness:         info.Name,
		DisplayName:     harnessDisplayName(info.Name),
		Status:          statusStr,
		AuthState:       providerAuthStateStr(signal),
		Models:          models,
		HistoricalUsage: historicalUsage,
		BurnEstimate:    burnEstimate,
		RoutingSignals: ProviderRoutingSignals{
			Availability: statusStr,
			RequestFit:   providerRequestFitStrInfo(info),
			CostEstimate: "unknown",
			Performance:  perf,
		},
		SignalSources: sources,
		FreshnessTS:   freshnessTS,
	}
}

func buildModelQuotaList(info agentlib.HarnessInfo, signal agent.RoutingSignalSnapshot) []ProviderModelQuota {
	models := harnessDefaultModels(info.Name)
	if len(models) == 0 {
		return []ProviderModelQuota{}
	}

	quotaState := providerQuotaHeadroomStr(signal)
	sourceEnum := signalSourceAPIEnum(signal.Source.Kind)
	var sourceNote string
	if quotaState == "unknown" && info.Name == "claude" {
		sourceNote = "no stable non-PTY quota source confirmed"
	}

	result := make([]ProviderModelQuota, 0, len(models))
	for _, m := range models {
		result = append(result, ProviderModelQuota{
			Model:         m,
			QuotaHeadroom: quotaState,
			Source:        sourceEnum,
			SourceNote:    sourceNote,
		})
	}
	return result
}

func computeProviderHistoricalUsage(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes7d []agent.RoutingOutcome,
	outcomes30d []agent.RoutingOutcome,
) *ProviderHistoricalUsage {
	window7d := usageWindowFromSignalOrOutcomes(info, signal, outcomes7d)
	window30d := usageWindowFromOutcomes(info, outcomes30d)
	if window7d == nil && window30d == nil {
		return nil
	}
	return &ProviderHistoricalUsage{
		Window7D:  window7d,
		Window30D: window30d,
	}
}

func usageWindowFromSignalOrOutcomes(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes []agent.RoutingOutcome,
) *ProviderUsageWindow {
	// Prefer provider-native signal if it has token data.
	if signal.HistoricalUsage.TotalTokens > 0 || signal.HistoricalUsage.InputTokens > 0 {
		w := &ProviderUsageWindow{
			InputTokens:  signal.HistoricalUsage.InputTokens,
			OutputTokens: signal.HistoricalUsage.OutputTokens,
			TotalTokens:  signal.HistoricalUsage.TotalTokens,
		}
		if info.IsSubscription || info.IsLocal {
			w.CostUSD = 0
			if info.IsSubscription {
				w.CostNote = "subscription plan; per-token cost not billed"
			}
		} else {
			w.CostUSD = -1
		}
		return w
	}
	return usageWindowFromOutcomes(info, outcomes)
}

func usageWindowFromOutcomes(info agentlib.HarnessInfo, outcomes []agent.RoutingOutcome) *ProviderUsageWindow {
	if len(outcomes) == 0 {
		return nil
	}
	var inTok, outTok int
	var costUSD float64
	hasCost := false
	for _, o := range outcomes {
		inTok += o.InputTokens
		outTok += o.OutputTokens
		if o.CostUSD > 0 {
			costUSD += o.CostUSD
			hasCost = true
		}
	}
	if inTok == 0 && outTok == 0 {
		return nil
	}
	w := &ProviderUsageWindow{
		InputTokens:  inTok,
		OutputTokens: outTok,
		TotalTokens:  inTok + outTok,
	}
	if info.IsSubscription || info.IsLocal {
		w.CostUSD = 0
		if info.IsSubscription {
			w.CostNote = "subscription plan; per-token cost not billed"
		}
	} else if hasCost {
		w.CostUSD = costUSD
	} else {
		w.CostUSD = -1
	}
	return w
}

func computeProviderBurnEstimate(
	info agentlib.HarnessInfo,
	burnSummaries []agent.BurnSummary,
	usage *ProviderHistoricalUsage,
	signal agent.RoutingSignalSnapshot,
) *ProviderBurnEstimate {
	if !info.IsSubscription {
		return nil
	}

	// Find the most recent burn summary for this harness.
	var latestBurn *agent.BurnSummary
	for i := range burnSummaries {
		if burnSummaries[i].Harness == info.Name {
			if latestBurn == nil || burnSummaries[i].ObservedAt.After(latestBurn.ObservedAt) {
				latestBurn = &burnSummaries[i]
			}
		}
	}

	// Derive daily token rate from 7d window (DDx-observed or provider-native).
	dailyTokenRate := -1.0
	if usage != nil && usage.Window7D != nil && usage.Window7D.TotalTokens > 0 {
		dailyTokenRate = float64(usage.Window7D.TotalTokens) / 7.0
	}

	// Require at least one data source before emitting a burn estimate.
	if latestBurn == nil && dailyTokenRate < 0 {
		return nil
	}

	// Determine source attribution.
	sourceEnum := signalSourceAPIEnum(signal.Source.Kind)
	var sourceStr string
	if latestBurn != nil && dailyTokenRate >= 0 {
		if sourceEnum != "none" {
			sourceStr = sourceEnum + "+ddx-metrics"
		} else {
			sourceStr = "ddx-metrics"
		}
	} else if latestBurn != nil {
		if sourceEnum != "none" {
			sourceStr = sourceEnum
		} else {
			sourceStr = "ddx-metrics"
		}
	} else {
		sourceStr = "ddx-metrics"
	}

	subscriptionBurn := "unknown"
	confidence := "low"
	var freshnessTS string

	if latestBurn != nil {
		switch {
		case latestBurn.BurnIndex >= 0.8:
			subscriptionBurn = "high"
		case latestBurn.BurnIndex >= 0.5:
			subscriptionBurn = "moderate"
		case latestBurn.BurnIndex >= 0.1:
			subscriptionBurn = "low"
		}
		switch {
		case latestBurn.Confidence >= 0.8:
			confidence = "high"
		case latestBurn.Confidence >= 0.5:
			confidence = "medium"
		}
		if !latestBurn.ObservedAt.IsZero() {
			freshnessTS = latestBurn.ObservedAt.UTC().Format(time.RFC3339)
		}
	}

	return &ProviderBurnEstimate{
		DailyTokenRate:   dailyTokenRate,
		SubscriptionBurn: subscriptionBurn,
		Source:           sourceStr,
		Confidence:       confidence,
		FreshnessTS:      freshnessTS,
	}
}

