var loadRoutingCatalog = modelcatalog.Default

// ResolveRoute resolves an under-specified RouteRequest to a concrete
// (Harness, Provider, Model) decision per CONTRACT-003.
//
// The implementation delegates to internal/routing.Resolve — the single
// routing engine that consolidates DDx-side harness-tier ranking and
// agent-side provider failover ordering.
func (s *service) ResolveRoute(ctx context.Context, req RouteRequest) (*RouteDecision, error) {
	if err := ValidatePowerBounds(req.MinPower, req.MaxPower); err != nil {
		return nil, err
	}
	if err := ValidateRole(req.Role); err != nil {
		return nil, err
	}
	if err := ValidateCorrelationID(req.CorrelationID); err != nil {
		return nil, err
	}
	s.ensurePrimaryQuotaRefresh(ctx, quotaRefreshAsync)
	cat := serviceRoutingCatalog()
	profile := req.Profile
	if profile == "" {
		profile = reqProfileFromModelRef(cat, req.ModelRef)
	}
	modelRef := reqModelRefStripProfile(cat, req.ModelRef)
	providerPreference, err := providerPreferenceForProfile(cat, profile)
	if err != nil {
		return &RouteDecision{}, err
	}
	in := s.buildRoutingInputsWithCatalog(ctx, cat)

	rReq := routing.Request{
		Profile:               profile,
		ModelRef:              modelRef,
		Model:                 req.Model,
		Provider:              req.Provider,
		Harness:               req.Harness,
		Reasoning:             effectiveReasoningString(req.Reasoning),
		Permissions:           req.Permissions,
		ProviderPreference:    providerPreference,
		EstimatedPromptTokens: req.EstimatedPromptTokens,
		RequiresTools:         req.RequiresTools,
		MinPower:              req.MinPower,
		MaxPower:              req.MaxPower,
	}
	s.applyRouteAttemptCooldowns(&in)
	dec, err := routing.Resolve(rReq, in)
	if err != nil {
		if escalated, edec, eerr := escalateProfileLadder(rReq, in, err); escalated {
			dec = edec
			err = eerr
		}
	}
	result := routeDecisionFromInternal(dec)
	if err != nil {
		if result == nil {
			result = &RouteDecision{}
		}
		return result, publicRoutingError(err, result.Candidates)
	}
	// Cache the decision so RouteStatus can surface LastDecision.
	if result != nil {
		result.Model = resolveSubprocessModelAlias(result.Harness, result.Model)
		result.Power = catalogPowerForModel(cat, result.Model)
	}
	s.cacheRouteDecision(req.Model, result)
	return result, nil
}

func routeDecisionFromInternal(dec *routing.Decision) *RouteDecision {
	if dec == nil {
		return nil
	}
	return &RouteDecision{
		Harness:    dec.Harness,
		Provider:   dec.Provider,
		Endpoint:   dec.Endpoint,
		Model:      dec.Model,
		Reason:     dec.Reason,
		Candidates: routeCandidatesFromInternal(dec.Candidates),
	}
}

func routeCandidatesFromInternal(candidates []routing.Candidate) []RouteCandidate {
	if len(candidates) == 0 {
		return nil
	}
	out := make([]RouteCandidate, len(candidates))
	for i, candidate := range candidates {
		out[i] = routeCandidateFromInternal(candidate)
	}
	return out
}

func routeCandidateFromInternal(candidate routing.Candidate) RouteCandidate {
	return RouteCandidate{
		Harness:            candidate.Harness,
		Provider:           candidate.Provider,
		Endpoint:           candidate.Endpoint,
		Model:              candidate.Model,
		Score:              candidate.Score,
		CostUSDPer1kTokens: candidate.CostUSDPer1kTokens,
		CostSource:         candidate.CostSource,
		Eligible:           candidate.Eligible,
		Reason:             candidate.Reason,
		FilterReason:       publicFilterReason(candidate),

			return nil
		},
	}
	cmd.Flags().Bool("connectivity", false, "Test provider connectivity and credit status")
	cmd.Flags().Bool("routing", false, "Probe and report full routing-relevant harness state (installed/reachable/auth/quota/degraded)")
	cmd.Flags().Bool("workers", false, "Show runtime worker registry (server-first; .ddx/workers/ fallback)")
	cmd.Flags().String("timeout", "", "Timeout for connectivity checks (default 15s)")
	cmd.Flags().Bool("json", false, "Output as JSON (with --routing or --workers)")
	return cmd
}

// harnessInfoToRoutingSignal translates an upstream HarnessInfo into the
// RoutingSignalSnapshot shape consumers still emit. Introduced when the
// DDx-side provider-native parsers were retired (ddx-7bc0c8d5): upstream
// quota.Status values ("ok|stale|unavailable") map to the existing
// freshness vocabulary so the JSON output for `ddx agent doctor --routing`
// keeps its previous field layout.
func harnessInfoToRoutingSignal(info agentlib.HarnessInfo, now time.Time) agent.RoutingSignalSnapshot {
	if info.Quota == nil && len(info.UsageWindows) == 0 && info.Account == nil {
		return agent.RoutingSignalSnapshot{}
	}

	snap := agent.RoutingSignalSnapshot{Provider: info.Name}
	if info.Account != nil && (info.Account.Email != "" || info.Account.PlanType != "" || info.Account.OrgName != "") {
		snap.Account = &agent.AccountInfo{
			Email:    info.Account.Email,
			PlanType: info.Account.PlanType,
			OrgName:  info.Account.OrgName,
		}
	}

	if info.Quota != nil {
		freshness := "fresh"
		if !info.Quota.Fresh {
			freshness = "stale"
		}
		if info.Quota.Status == "unavailable" || info.Quota.Status == "unauthenticated" {
			freshness = "unknown"
		}
		kind := info.Quota.Source
		if kind == "" {
			kind = "stats-cache"
		}
		var ageSeconds int64
		if !info.Quota.CapturedAt.IsZero() {
			if age := now.UTC().Sub(info.Quota.CapturedAt.UTC()); age > 0 {
				ageSeconds = int64(age.Seconds())
			}
		}
		meta := agent.SignalSourceMetadata{
			Provider:   info.Name,
			Kind:       kind,
			ObservedAt: info.Quota.CapturedAt.UTC(),
			Freshness:  freshness,
			AgeSeconds: ageSeconds,
		}
		state := "unknown"
		switch info.Quota.Status {
		case "ok":
			state = "ok"
		case "stale":
			state = "ok"
		}
		var usedPercent, windowMinutes int
		var resetsAt string
		for _, w := range info.Quota.Windows {
			snap.QuotaWindows = append(snap.QuotaWindows, agent.QuotaWindow{
				Name:          w.Name,
				LimitID:       w.LimitID,
				WindowMinutes: w.WindowMinutes,
				UsedPercent:   w.UsedPercent,
				ResetsAt:      w.ResetsAt,
				ResetsAtUnix:  w.ResetsAtUnix,
				State:         w.State,
			})
			if w.LimitID == "extra" {
				continue
			}
			if w.State == "blocked" {
				state = "blocked"
				resetsAt = w.ResetsAt

				resetsAt = w.ResetsAt
			}
			if int(w.UsedPercent+0.5) > usedPercent {
				usedPercent = int(w.UsedPercent + 0.5)
				windowMinutes = w.WindowMinutes
			}
		}
		snap.Source = meta
		snap.CurrentQuota = agent.QuotaSignal{
			Source:        meta,
			State:         state,
			UsedPercent:   usedPercent,
			WindowMinutes: windowMinutes,
			ResetsAt:      resetsAt,
		}
		snap.HistoricalUsage.Source = meta
	}

	for _, u := range info.UsageWindows {
		snap.HistoricalUsage.InputTokens += u.InputTokens
		snap.HistoricalUsage.OutputTokens += u.OutputTokens
		snap.HistoricalUsage.TotalTokens += u.TotalTokens
	}

	return snap
}

